    Effect.gen(function* () {
      const tagShas = yield* Ref.get(state.tagShas)
      const sha = tagShas[tag]
      if (!sha) {
        const detail = `tag not found: ${tag}`
        return yield* Effect.fail(
          new GitError({
            context: { operation: 'getTagSha', detail },
            cause: new Error(detail),
          }),
        )
      }
      return sha
    })"}]

